#!/bin/bash\n# launch_app.sh - Script de lancement complet avec diagnostics\n\nset -e\n\necho \"🚀 SWIFT Engine - Lancement Complet\"\necho \"===================================\"\n\n# Couleurs\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nRED='\\033[0;31m'\nNC='\\033[0m' # No Color\n\n# 1. Activer l'environnement\necho -e \"${YELLOW}1️⃣  Activation de l'environnement Python...${NC}\"\nif [ ! -d \".venv\" ]; then\n    echo -e \"${RED}❌ Environnement .venv non trouvé${NC}\"\n    exit 1\nfi\nsource .venv/bin/activate\necho -e \"${GREEN}✅ Environnement activé${NC}\\n\"\n\n# 2. Vérifier Ollama\necho -e \"${YELLOW}2️⃣  Diagnostic Ollama...${NC}\"\nif python3 monitor_ollama.py 2>/dev/null | grep -q \"✅ Ollama fonctionne normalement\"; then\n    echo -e \"${GREEN}✅ Ollama OK${NC}\\n\"\nelse\n    echo -e \"${YELLOW}⚠️  Ollama peut avoir des problèmes${NC}\"\n    echo -e \"${YELLOW}   → Voir monitor_ollama.py pour plus de détails${NC}\\n\"\nfi\n\n# 3. Pré-charger le modèle (optionnel)\necho -e \"${YELLOW}3️⃣  Pré-charge du modèle Ollama...${NC}\"\nif python3 preload_ollama_model.py 2>/dev/null | grep -q \"✅ Modèle pré-chargé\"; then\n    echo -e \"${GREEN}✅ Modèle pré-chargé${NC}\\n\"\nelse\n    echo -e \"${YELLOW}⚠️  Pré-charge échouée (non critique)${NC}\\n\"\nfi\n\n# 4. Tester les fixes E3\necho -e \"${YELLOW}4️⃣  Test des fixes E3 HTTP 500...${NC}\"\nif python3 test_e3_quick.py 2>/dev/null | grep -q \"✅ Tests terminés\"; then\n    echo -e \"${GREEN}✅ Fixes E3 OK${NC}\\n\"\nelse\n    echo -e \"${RED}❌ Tests E3 échoués${NC}\\n\"\n    exit 1\nfi\n\n# 5. Lancer Streamlit\necho -e \"${GREEN}5️⃣  Lancement de Streamlit...${NC}\"\necho -e \"${GREEN}========================${NC}\"\necho -e \"\\n🌐 L'app ouvre sur: http://localhost:8501\\n\"\n\nstreamlit run app/streamlit_app2.py\n